scripts.script:
function series() {
  var out = []
  var v = 2200
  for (var i = 0; i < 60; i++) {
    v += Math.sin(i / 4) * 55 + (i * 5) - 6
    out.push([i, Math.round(v)])
  }
  return out
}

html:
Right-click anywhere on the plot to open the actions menu.
{{ charts[0] }}
Right-click (or long-press) the plot to open an anchored actions menu. Because each verb receives the clicked data point, it acts right there, not chart-wide like a toolbar button: Add note here drops an editable, draggable callout at the click and opens its floating editor (type to rename; the card also offers accent colors, bold, text size, marker size/shape and delete, via chart.ink). Annotate here drops a dashed vertical line at the clicked x, and Mark this level a dashed horizontal line at the clicked y: always a line, never a rectangle, styled via contextMenu.line (label text, dash pattern, color) and just as draggable, restylable and undoable as the note. A line's editor card has separate Label and Line color rows, so a white label chip never blanks the stroke. Click any note or line later to reopen its editor. Measure from here seeds the ruler at the click, then a second click completes the measurement (chart.measure). The Copy value entry below is a custom item wired via contextMenu.items[].onClick. Arrow keys move, Enter activates, Escape closes.

chart.options:
chart: {
  id: 'ctxmenu',
  type: 'line',
  height: 400,
  fontFamily: 'Helvetica, Arial, sans-serif',
  animations: { enabled: false },
  toolbar: { show: false },
  zoom: { enabled: true, type: 'x' },
  contextMenu: {
    enabled: true,
    line: { text: 'Event', strokeDashArray: 5, color: '#7c3aed' },
    items: [
      'annotate',
      'xline',
      'yline',
      'measure',
      {
        id: 'copyValue',
        label: 'Copy value',
        onClick: function (chart, ctx) {
          var msg = 'x=' + Math.round(ctx.x) + ', y=' + Math.round(ctx.y)
          var readout = document.getElementById('cm-readout')
          if (readout) readout.textContent = 'Copied ' + msg
          if (navigator.clipboard) navigator.clipboard.writeText(msg).catch(function () {})
        },
      },
    ],
  },
  measure: { enabled: true },
  ink: { enabled: true },
},
stroke: { width: 2, curve: 'smooth' },
colors: ['#2563eb'],
dataLabels: { enabled: false },
title: { text: 'Revenue (right-click to add notes or measure)', align: 'left' },
xaxis: { type: 'numeric', title: { text: 'Session' } },
yaxis: { title: { text: 'Revenue' }, decimalsInFloat: 0 },

vanilla-js-script:
var readout = document.getElementById('cm-readout')
chart.addEventListener('measured', function (c, o) {
  readout.textContent =
    'Measured: dy=' + Number(o.dy).toFixed(0) +
    ' (' + (o.percentChange >= 0 ? '+' : '') + Number(o.percentChange).toFixed(1) + '%)'
})
chart.addEventListener('annotationCreated', function (c, o) {
  var kind = o && o.type === 'xaxis' ? 'Dashed line' : o && o.type === 'yaxis' ? 'Level line' : 'Note'
  readout.textContent =
    kind + ' added. Type to rename it; the floating card restyles or deletes it. Drag to move.'
})

react-script:
React.useEffect(() => {
  // The react-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id, then wire the same readout events the vanilla build does.
  // (The context menu, ink and measure config all live in the chart options.)
  let chart
  const timer = window.setInterval(() => {
    chart = ApexCharts.getChartByID('ctxmenu')
    if (!chart) return
    window.clearInterval(timer)

    const readout = document.getElementById('cm-readout')
    chart.addEventListener('measured', (c, o) => {
      readout.textContent =
        'Measured: dy=' + Number(o.dy).toFixed(0) +
        ' (' + (o.percentChange >= 0 ? '+' : '') + Number(o.percentChange).toFixed(1) + '%)'
    })
    chart.addEventListener('annotationCreated', (c, o) => {
      const kind = o && o.type === 'xaxis' ? 'Dashed line' : o && o.type === 'yaxis' ? 'Level line' : 'Note'
      readout.textContent =
        kind + ' added. Type to rename it; the floating card restyles or deletes it. Drag to move.'
    })
  }, 50)

  return () => window.clearInterval(timer)
}, [])

vue-script:
mounted: function () {
  // The vue-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id, then wire the same readout events the vanilla build does.
  // (The context menu, ink and measure config all live in the chart options.)
  var me = this
  me.ctxTimer = window.setInterval(function () {
    var chart = ApexCharts.getChartByID('ctxmenu')
    if (!chart) return
    window.clearInterval(me.ctxTimer)

    var readout = document.getElementById('cm-readout')
    chart.addEventListener('measured', function (c, o) {
      readout.textContent =
        'Measured: dy=' + Number(o.dy).toFixed(0) +
        ' (' + (o.percentChange >= 0 ? '+' : '') + Number(o.percentChange).toFixed(1) + '%)'
    })
    chart.addEventListener('annotationCreated', function (c, o) {
      var kind = o && o.type === 'xaxis' ? 'Dashed line' : o && o.type === 'yaxis' ? 'Level line' : 'Note'
      readout.textContent =
        kind + ' added. Type to rename it; the floating card restyles or deletes it. Drag to move.'
    })
  }, 50)
},
beforeDestroy: function () {
  window.clearInterval(this.ctxTimer)
},
